import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ArrowUpward, ArrowDownward } from '@mui/icons-material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface FunnelStage {
  stage: string;
  rate: number;
  previousRate: number;
}

interface ConversionData {
  funnelStages: FunnelStage[];
  comparison: {
    currentConversion: number;
    previousConversion: number;
  };
}

export default function Widget() {
  const { funnelStages, comparison } = response.data as ConversionData;
  const isConversionImproved = comparison.currentConversion >= comparison.previousConversion;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#2E2E2E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 0.5 }}>
              Conversion Funnel
            </Typography>
            <Typography variant="h4" sx={{ color: '#FF5722', fontWeight: 600 }}>
              {comparison.currentConversion}%
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isConversionImproved ? (
                <ArrowUpward sx={{ fontSize: 16, color: '#FFC107' }} />
              ) : (
                <ArrowDownward sx={{ fontSize: 16, color: '#FFC107' }} />
              )}
              <Typography variant="body2" sx={{ color: '#FFC107' }}>
                {Math.abs(comparison.currentConversion - comparison.previousConversion)}% from last period
              </Typography>
            </Stack>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: funnelStages.map(stage => stage.rate),
                color: '#FFC107',
              },
            ]}
            xAxis={[
              {
                data: funnelStages.map(stage => stage.stage),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#FFFFFF',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />

          <Stack direction="row" spacing={1} justifyContent="space-between">
            {funnelStages.map((stage, index) => (
              <Box key={index}>
                <Typography variant="caption" sx={{ color: '#FFC107' }}>
                  {stage.stage}
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                  {stage.rate}%
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
